endpoints.nodeNativeHttps:
import https from "node:https";

const body = JSON.stringify({
  mobile: "919876543210",
  templateid: "1036659577939498"
});

const baseUrl = new URL(process.env.CUNNEKT_BASE_URL);

const request = https.request(
  {
    protocol: baseUrl.protocol,
    hostname: baseUrl.hostname,
    port: baseUrl.port || 443,
    path: `${baseUrl.pathname.replace(/\/$/, "")}/whatsapp/sendtemplate`,
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Content-Length": Buffer.byteLength(body),
      "API-KEY": process.env.CUNNEKT_API_KEY
    },
    timeout: 15000
  },
  (response) => {
    let raw = "";

    response.setEncoding("utf8");
    response.on("data", (chunk) => {
      raw += chunk;
    });

    response.on("end", () => {
      let parsed;
      try {
        parsed = raw ? JSON.parse(raw) : null;
      } catch {
        parsed = raw;
      }

      if (
        response.statusCode === undefined ||
        response.statusCode < 200 ||
        response.statusCode >= 300
      ) {
        console.error("Cunnekt request failed", {
          statusCode: response.statusCode,
          body: parsed
        });
        return;
      }

      console.log(parsed);
    });
  }
);

request.on("timeout", () => {
  request.destroy(new Error("Cunnekt request timed out"));
});

request.on("error", (error) => {
  console.error("Cunnekt request error:", error.message);
});

request.write(body);
request.end();
